// extract.js
// Parse an ELF64 binary, map its PT_LOAD segments at CLE/angr's default
// PIE base (0x400000), and emit every 4-byte little-endian word as
// { <address>: <uint32> }.

const fs = require('fs');

const path = process.argv[2];
if (!path) {
  process.stderr.write('usage: node extract.js <binary>\n');
  process.exit(1);
}

const buf = fs.readFileSync(path);

// ELF header sanity check.
if (buf.length < 64 || buf[0] !== 0x7f || buf[1] !== 0x45 || buf[2] !== 0x4c || buf[3] !== 0x46) {
  process.stderr.write('not an ELF file\n');
  process.exit(1);
}

const is64 = buf[4] === 2; // EI_CLASS: 2 = ELFCLASS64
if (!is64) {
  process.stderr.write('only ELF64 supported\n');
  process.exit(1);
}

// Program header table location (ELF64 little-endian).
const e_phoff = Number(buf.readBigUInt64LE(0x20));
const e_phentsize = buf.readUInt16LE(0x36);
const e_phnum = buf.readUInt16LE(0x38);

const PT_LOAD = 1;
const BASE = 0x400000; // CLE/angr default base address for PIE objects

const out = {};

for (let i = 0; i < e_phnum; i++) {
  const ph = e_phoff + i * e_phentsize;
  const p_type = buf.readUInt32LE(ph);
  if (p_type !== PT_LOAD) continue;

  const p_offset = Number(buf.readBigUInt64LE(ph + 0x08));
  const p_vaddr = Number(buf.readBigUInt64LE(ph + 0x10));
  const p_filesz = Number(buf.readBigUInt64LE(ph + 0x20));

  const segBase = BASE + p_vaddr;

  // Emit full 4-byte aligned words backed by file content.
  for (let off = 0; off + 4 <= p_filesz; off += 4) {
    const fileOff = p_offset + off;
    if (fileOff + 4 > buf.length) break;
    const addr = segBase + off;
    out[addr] = buf.readUInt32LE(fileOff);
  }
}

process.stdout.write(JSON.stringify(out));
